/*
 * Priority Queue Implementations in C
 * Demonstrates: Unsorted Array vs Sorted Array
 * 
 * Topic: Priority Queues - CSE 2022 Scheme
 * 
 * Unsorted Array: Insert O(1), DeleteMin O(n)
 * Sorted Array: Insert O(n), DeleteMin O(1)
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SIZE 100

// Structure for priority queue element
typedef struct {
 int data; // The actual data
 int priority; // Priority value (lower = higher priority for min-PQ)
} PQElement;

// ============== UNSORTED ARRAY IMPLEMENTATION ==============
typedef struct {
 PQElement items[MAX_SIZE];
 int size;
} UnsortedPQ;

void initUnsortedPQ(UnsortedPQ *pq) {
 pq->size = 0;
}

bool isEmptyUnsorted(UnsortedPQ *pq) {
 return pq->size == 0;
}

// Insert: O(1) - just append at end
void insertUnsorted(UnsortedPQ *pq, int data, int priority) {
 if (pq->size >= MAX_SIZE) {
 printf("Queue is full!\n");
 return;
 }
 pq->items[pq->size].data = data;
 pq->items[pq->size].priority = priority;
 pq->size++;
 printf("Inserted: %d with priority %d\n", data, priority);
}

// Find index of minimum: O(n)
int findMinIndex(UnsortedPQ *pq) {
 int minIndex = 0;
 for (int i = 1; i < pq->size; i++) {
 if (pq->items[i].priority < pq->items[minIndex].priority) {
 minIndex = i;
 }
 }
 return minIndex;
}

// DeleteMin: O(n) - must find min first
int deleteMinUnsorted(UnsortedPQ *pq) {
 if (isEmptyUnsorted(pq)) {
 printf("Queue is empty!\n");
 return -1;
 }

 int minIndex = findMinIndex(pq); // O(n) search
 int deletedData = pq->items[minIndex].data;

 // Remove by swapping with last element
 pq->items[minIndex] = pq->items[pq->size - 1];
 pq->size--;

 return deletedData;
}

// ============== SORTED ARRAY IMPLEMENTATION ==============
typedef struct {
 PQElement items[MAX_SIZE];
 int size;
} SortedPQ;

void initSortedPQ(SortedPQ *pq) {
 pq->size = 0;
}

bool isEmptySorted(SortedPQ *pq) {
 return pq->size == 0;
}

// Insert: O(n) - find position and shift elements
void insertSorted(SortedPQ *pq, int data, int priority) {
 if (pq->size >= MAX_SIZE) {
 printf("Queue is full!\n");
 return;
 }

 int i = pq->size - 1;

 // Shift elements with smaller priority (higher priority) to right
 // Array stores in DESCENDING order for min-PQ (smallest at end)
 while (i >= 0 && pq->items[i].priority < priority) {
 pq->items[i + 1] = pq->items[i];
 i--;
 }

 pq->items[i + 1].data = data;
 pq->items[i + 1].priority = priority;
 pq->size++;
 printf("Inserted: %d with priority %d\n", data, priority);
}

// DeleteMin: O(1) - remove from end (smallest priority)
int deleteMinSorted(SortedPQ *pq) {
 if (isEmptySorted(pq)) {
 printf("Queue is empty!\n");
 return -1;
 }

 // Since array is sorted in descending priority order,
 // smallest priority (highest priority) is at the END
 int deletedData = pq->items[pq->size - 1].data;
 pq->size--;

 return deletedData;
}

// Peek: O(1) - look at end for sorted, scan for unsorted
int peekSorted(SortedPQ *pq) {
 if (isEmptySorted(pq)) return -1;
 return pq->items[pq->size - 1].data; // Smallest is at end
}

// ============== DEMONSTRATION ==============
void printDivider() {
 printf("\n=====================================\n");
}

int main() {
 printf("PRIORITY QUEUE IMPLEMENTATION COMPARISON\n");
 printf("Lower priority value = Higher priority\n");

 // ===== UNSORTED ARRAY DEMO =====
 printDivider();
 printf("UNSORTED ARRAY IMPLEMENTATION\n");
 printf("Insert: O(1) | DeleteMin: O(n)\n");
 printDivider();

 UnsortedPQ unsortedPQ;
 initUnsortedPQ(&unsortedPQ);

 insertUnsorted(&unsortedPQ, "Task A", 3);
 insertUnsorted(&unsortedPQ, "Task B", 1);
 insertUnsorted(&unsortedPQ, "Task C", 5);
 insertUnsorted(&unsortedPQ, "Task D", 2);

 printf("\nDeleting in priority order:\n");
 while (!isEmptyUnsorted(&unsortedPQ)) {
 int data = deleteMinUnsorted(&unsortedPQ);
 printf(" Deleted: %d\n", data);
 }

 // ===== SORTED ARRAY DEMO =====
 printDivider();
 printf("SORTED ARRAY IMPLEMENTATION\n");
 printf("Insert: O(n) | DeleteMin: O(1)\n");
 printDivider();

 SortedPQ sortedPQ;
 initSortedPQ(&sortedPQ);

 insertSorted(&sortedPQ, 10, 3);
 insertSorted(&sortedPQ, 20, 1);
 insertSorted(&sortedPQ, 30, 5);
 insertSorted(&sortedPQ, 40, 2);

 printf("\nDeleting in priority order:\n");
 while (!isEmptySorted(&sortedPQ)) {
 int data = deleteMinSorted(&sortedPQ);
 printf(" Deleted: %d\n", data);
 }

 // ===== COMPLEXITY SUMMARY =====
 printDivider();
 printf("TIME COMPLEXITY COMPARISON\n");
 printDivider();
 printf("%-15s %10s %10s\n", "Operation", "Unsorted", "Sorted");
 printf("%-15s %10s %10s\n", "---------------", "---------", "---------");
 printf("%-15s %10s %10s\n", "Insert", "O(1)", "O(n)");
 printf("%-15s %10s %10s\n", "DeleteMin", "O(n)", "O(1)");
 printf("%-15s %10s %10s\n", "Peek", "O(n)", "O(1)");

 return 0;
}
